{
  "grammar": [
    {
      "pattern": "喂，請問 + [person/place] + 在嗎？",
      "structure": ["喂", "請問", "person/place", "在嗎"],
      "explanation_en": "Use this polite opening to ask if someone is available or if a place is open when calling.",
      "title": "Polite Phone Opening: 喂，請問...在嗎？",
      "meaning": "Hello, may I ask if [person/place] is there?",
      "when_to_use": ["When calling a friend or colleague to check if they are available", "When calling a shop or clinic to confirm they are open"],
      "when_not_to_use": ["When you already know the person is available", "In very informal or urgent situations"],
      "pragmatic_notes": "In Taiwan, starting a phone call with 喂 (wéi) is standard. Adding 請問 makes it polite. For shops, you can say 請問你們在營業嗎？",
      "word_order_notes": "喂 comes first, then 請問, then the person/place, then 在嗎.",
      "english_contrast": "English says 'Hello, is [person] there?' without a separate politeness marker. Chinese uses 請問 to show respect.",
      "korean_contrast": "Korean uses 여보세요 (yeoboseyo) + [name] + 계세요? which is similar but 請問 is more explicit in politeness.",
      "negative_examples": [
        {
          "text": "喂，你嗎？",
          "error": "Missing 請問 and 在, making it too abrupt and unclear."
        },
        {
          "text": "請問喂，在嗎？",
          "error": "Word order is wrong; 喂 must come first."
        }
      ],
      "incorrect_examples": [
        {
          "text": "喂，請問你嗎？",
          "error": "Using 你嗎 is incorrect; should be 在嗎 for availability."
        }
      ],
      "transformation_drills": ["Change '朋友' to '診所' and adjust the sentence.", "Change to a shop: 喂，請問你們在營業嗎？"],
      "production_drills": ["Call a friend: 喂，請問小明在嗎？", "Call a clinic: 喂，請問診所在嗎？"],
      "common_error_patterns": ["Forgetting 喂 at the start", "Using 你嗎 instead of 在嗎"],
      "repair_feedback": {
        "word_order": "Remember: 喂 first, then 請問, then the person/place, then 在嗎.",
        "politeness": "Always include 請問 to sound polite on the phone.",
        "vocabulary": "Use 在嗎 for availability, not 你嗎."
      }
    },
    {
      "pattern": "我想 + [verb phrase] + ，請問 + [question]？",
      "structure": ["我想", "verb phrase", "，請問", "question"],
      "explanation_en": "Use this to express your intention (e.g., to make a reservation or order) and then ask a polite question.",
      "title": "Expressing Intent with 我想 and 請問",
      "meaning": "I would like to [do something], may I ask [question]?",
      "when_to_use": ["When calling a restaurant to make a reservation", "When calling a clinic to schedule an appointment", "When calling a shop to inquire about products or services"],
      "when_not_to_use": ["When the action is already clear from context", "In very casual conversations with close friends"],
      "pragmatic_notes": "In Taiwan, using 我想 shows your intention politely, and 請問 softens the question. Common in service calls.",
      "word_order_notes": "Start with 我想, then the verb phrase, then a comma, then 請問, then the question.",
      "english_contrast": "English often says 'I'd like to... Can I ask...?' Chinese combines them with 我想 and 請問.",
      "korean_contrast": "Korean uses ~고 싶은데요 + 여쭤볼게요, which is similar but 請問 is more direct.",
      "negative_examples": [
        {
          "text": "我想預約，請問？",
          "error": "Missing the specific question after 請問; it's incomplete."
        },
        {
          "text": "請問我想預約？",
          "error": "Word order is wrong; 我想 should come before 請問."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想預約，請問你嗎？",
          "error": "Using 你嗎 is incorrect; should be a specific question like 請問可以嗎？"
        }
      ],
      "transformation_drills": ["Change '預約' to '外帶' and adjust the question.", "Change to a clinic: 我想掛號，請問今天可以看診嗎？"],
      "production_drills": ["Call a restaurant: 我想訂位，請問晚上還有位子嗎？", "Call a shop: 我想外帶，請問營業到幾點？"],
      "common_error_patterns": ["Forgetting the comma between 我想 and 請問", "Using 你嗎 instead of a specific question"],
      "repair_feedback": {
        "word_order": "Place 我想 first, then the action, then 請問, then the question.",
        "politeness": "Using 請問 after 我想 makes the request polite.",
        "vocabulary": "Use specific questions like 可以嗎 or 有嗎 instead of 你嗎."
      }
    },
    {
      "pattern": "不好意思，我打錯了。",
      "structure": ["不好意思", "，", "我", "打錯了"],
      "explanation_en": "Use this to apologize when you dial the wrong number.",
      "title": "Apologizing for Wrong Number: 不好意思，我打錯了。",
      "meaning": "Sorry, I dialed the wrong number.",
      "when_to_use": ["When you realize you have called the wrong person or place", "After the other person says you have the wrong number"],
      "when_not_to_use": ["When you are sure you have the right number", "In very formal written communication"],
      "pragmatic_notes": "In Taiwan, 不好意思 is a common polite apology. 打錯了 specifically means 'dialed wrong'. It's polite to say this and then hang up.",
      "word_order_notes": "Start with 不好意思, then a comma, then 我打錯了.",
      "english_contrast": "English says 'Sorry, wrong number.' Chinese adds 我 (I) to clarify who made the mistake.",
      "korean_contrast": "Korean uses 죄송합니다, 잘못 걸었습니다. which is similar but 不好意思 is more casual-polite.",
      "negative_examples": [
        {
          "text": "我打錯了。",
          "error": "Missing 不好意思, which makes it less polite."
        },
        {
          "text": "不好意思，打錯。",
          "error": "Missing 了 to indicate the action is completed."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，我打錯電話。",
          "error": "Missing 了; should be 打錯了 to show the mistake happened."
        }
      ],
      "transformation_drills": ["Change to a more formal apology: 對不起，我打錯了。", "Add a follow-up: 不好意思，我打錯了，對不起。"],
      "production_drills": ["When you call a wrong number: 不好意思，我打錯了。", "When someone says you have the wrong number: 不好意思，我打錯了。"],
      "common_error_patterns": ["Forgetting 了 at the end", "Using 對不起 instead of 不好意思 (both are fine, but 不好意思 is more common in casual calls)"],
      "repair_feedback": {
        "word_order": "Start with 不好意思, then 我打錯了.",
        "politeness": "Always include 不好意思 to apologize politely.",
        "vocabulary": "Use 打錯了 for wrong number, not just 錯了."
      }
    }
  ]
}
